import React, { useContext, useState } from 'react';
import UserContext from '../../context/UserContext';
import PROFILE from '../../mock/profile';
import './style.css';

export default function ProfilePage() {
  const user = useContext(UserContext);
  const [profile, setProfile] = useState(PROFILE);
  const [isEditing, setIsEditing] = useState(false);
  const [formState, setFormState] = useState({
    title: PROFILE.title,
    description: PROFILE.description,
    overviewTitle: PROFILE.overviewTitle,
    overviewText: PROFILE.overviewText,
  });

  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setFormState((prev) => ({ ...prev, [name]: value }));
  };

  const handleOpenEditor = () => {
    setFormState({
      title: profile.title,
      description: profile.description,
      overviewTitle: profile.overviewTitle,
      overviewText: profile.overviewText,
    });
    setIsEditing(true);
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    setProfile((prev) => ({ ...prev, ...formState }));
    setIsEditing(false);
  };

  return (
    <main className="profile-page">
      <section className="profile-hero">
        <div className="profile-card profile-main">
          <div className="profile-avatar">
            <img src={profile.imageUrl} alt={profile.imageAlt} className="profile-avatar-image" />
            <span className="profile-avatar-badge">{profile.initials}</span>
          </div>

          <div className="profile-copy">
            <p className="profile-kicker">Profile</p>
            <h1>{profile.title}</h1>
            <p className="profile-text">{profile.description}</p>
            <div className="profile-context-banner">
              <strong>Context Demo:</strong> {user.name} - {user.role}
            </div>
            <div className="profile-tags">
              {profile.skills.map((skill) => (
                <span key={skill} className="profile-tag">{skill}</span>
              ))}
            </div>
            <div className="profile-actions">
              <button className="profile-button primary" onClick={handleOpenEditor}>
                {profile.editLabel}
              </button>
            </div>
          </div>
        </div>

        <aside className="profile-card profile-side">
          <p className="profile-kicker">Overview</p>
          <h2>{profile.overviewTitle}</h2>
          <p className="profile-text">{profile.overviewText}</p>
        </aside>
      </section>

      <section className="profile-grid">
        <div className="profile-card profile-details">
          <p className="profile-kicker">About</p>
          <h3>Profile Details</h3>
          <ul className="profile-list">
            {profile.details.map((item) => (
              <li key={item.label}><strong>{item.label}:</strong> {item.value}</li>
            ))}
          </ul>
        </div>

        <div className="profile-card profile-stats">
          <p className="profile-kicker">Stats</p>
          <div className="stats-grid">
            {profile.highlights.map((item) => (
              <div key={item.label} className="stat-box">
                <strong>{item.value}</strong>
                <span>{item.label}</span>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section className="profile-social-section">
        <div className="profile-card profile-socials">
          <p className="profile-kicker">Social Links</p>
          <h3>Find this profile around the web</h3>
          <div className="social-grid">
            {profile.socials.map((item) => (
              <a key={item.label} href={item.href} target="_blank" rel="noreferrer" className="social-card">
                <span className="social-label">{item.label}</span>
                <strong>{item.value}</strong>
              </a>
            ))}
          </div>
        </div>
      </section>

      {isEditing && (
        <div className="profile-modal-overlay" onClick={() => setIsEditing(false)}>
          <div className="profile-modal" onClick={(event) => event.stopPropagation()}>
            <div className="profile-modal-head">
              <div>
                <p className="profile-kicker">Edit Profile</p>
                <h3>Update your profile content</h3>
              </div>
              <button className="profile-close-button" onClick={() => setIsEditing(false)}>Close</button>
            </div>

            <form className="profile-form" onSubmit={handleSubmit}>
              <label className="profile-field">
                <span>Title</span>
                <input type="text" name="title" value={formState.title} onChange={handleInputChange} />
              </label>
              <label className="profile-field">
                <span>Description</span>
                <textarea name="description" value={formState.description} onChange={handleInputChange} rows="4" />
              </label>
              <label className="profile-field">
                <span>Overview Title</span>
                <input type="text" name="overviewTitle" value={formState.overviewTitle} onChange={handleInputChange} />
              </label>
              <label className="profile-field">
                <span>Overview Text</span>
                <textarea name="overviewText" value={formState.overviewText} onChange={handleInputChange} rows="4" />
              </label>

              <div className="profile-form-actions">
                <button type="button" className="profile-button secondary" onClick={() => setIsEditing(false)}>Cancel</button>
                <button type="submit" className="profile-button primary">Save Changes</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </main>
  );
}
